class Solution {
public:
    vector<vector<int>> validArrangement(vector<vector<int>>& pairs) {
        unordered_map<int, vector<int>> graph;
        unordered_map<int, int> in_degree;

        for (auto& pair : pairs) {
            graph[pair[0]].push_back(pair[1]);
            in_degree[pair[1]]++;
        }

        for (auto& pair : pairs) {
            if (in_degree[pair[0]] == 0) {
                vector<vector<int>> result;
                dfs(pair[0], graph, result);
                return result;
            }
        }

        return {};
    }

    void dfs(int node, unordered_map<int, vector<int>>& graph, vector<vector<int>>& result) {
        while (!graph[node].empty()) {
            int next_node = graph[node].back();
            graph[node].pop_back();
            dfs(next_node, graph, result);
            result.push_back({node, next_node});
        }
    }
};

